# OEIS sequence: A350134

from math import comb
def a_list(N: int) -> list[int]:
    K = [0] * (N + 1)
    F = [1] * (N + 1)
    for i in range(1, N + 1):
        F[i] = F[i-1] * i
    for i in range(1, N + 1):
        val = 0
        p = 1
        for k in range(i):
            val += p * (F[i-1] // F[k])
            p *= i
        K[i] = val
    C = [0] * (N + 1); C[0] = 1
    A = [0] * (N + 1); A[0] = 0
    for n in range(1, N + 1):
        c_n = 0
        for i in range(1, n + 1):
            c_n += K[i] * comb(n - 1, i - 1) * C[n - i]
        C[n] = c_n
        a_n = C[n - 1]
        for i in range(2, n + 1):
            a_n += K[i] * comb(n - 1, i - 1) * A[n - i]
        A[n] = a_n
    return A[:N]
print(a_list(20))  # _Peter Luschny_, Jun 13 2026

